sql:
SELECT RF_base_Completa_Hist_Input.* INTO RF_base_Completa_Hist
FROM RF_base_Completa_Hist_Input
WHERE (((RF_base_Completa_Hist_Input.Fec_Pro)>Date()-10) AND (((RF_base_Completa_Hist_Input.Cod_Pro) Not Like "*publico*") or ((RF_base_Completa_Hist_Input.Clasificacion_Contable) Not Like "htm")));
